//! lunaric.dev — a personal security/dev blog.
//! Hand-written in Rust, compiled to WebAssembly, served from Cloudflare's edge.

use comrak::{markdown_to_html, Options};
use serde::Deserialize;
use worker::wasm_bindgen::JsValue;
use worker::*;

// Generated by build.rs: `RAW_POSTS: &[(&str, &str)]` of (slug, raw markdown).
include!(concat!(env!("OUT_DIR"), "/posts_generated.rs"));

#[event(fetch)]
async fn fetch(req: Request, env: Env, _ctx: Context) -> Result<Response> {
    console_error_panic_hook::set_once();

    let resp = Router::new()
        .get("/", |_, _| Response::from_html(home_page()))
        .get("/whoami", |_, _| Response::from_html(layout("whoami", "whoami", SITE_DESC, "/whoami", "", WHOAMI)))
        .get("/blog", |_, _| Response::from_html(blog_index()))
        .get_async("/blog/:slug", |_, ctx| async move {
            let slug = match ctx.param("slug") {
                Some(s) => s.clone(),
                None => return Response::error("Not found", 404),
            };
            match find_post(&slug) {
                Some(p) => {
                    let views = bump_views(&ctx.env, &slug).await.unwrap_or(0);
                    Response::from_html(post_page(&p, views))
                }
                None => Response::error("Post not found", 404),
            }
        })
        .get("/projects", |_, _| Response::from_html(layout("projects", "projects", "Things I've built and broken.", "/projects", "", PROJECTS)))
        .get("/uses", |_, _| Response::from_html(layout("uses", "uses", "The gear and setup behind my homelab.", "/uses", "", USES)))
        .get_async("/guestbook", |_, ctx| async move {
            let entries = list_guestbook(&ctx.env).await.unwrap_or_default();
            Response::from_html(guestbook_page(&entries))
        })
        .post_async("/guestbook", |mut req, ctx| async move {
            let form = req.form_data().await?;
            // honeypot: real users never fill this hidden field; bots do.
            if !field(&form, "website").trim().is_empty() {
                return redirect_to("/guestbook");
            }
            let name = field(&form, "name");
            let message = field(&form, "message");
            if !message.trim().is_empty() {
                let _ = add_guestbook(&ctx.env, &name, &message).await;
            }
            redirect_to("/guestbook")
        })
        .get("/rss.xml", |_, _| {
            let mut r = Response::ok(rss())?;
            r.headers_mut().set("content-type", "application/rss+xml; charset=utf-8")?;
            Ok(r)
        })
        .get("/sitemap.xml", |_, _| {
            let mut r = Response::ok(sitemap())?;
            r.headers_mut().set("content-type", "application/xml; charset=utf-8")?;
            Ok(r)
        })
        .get("/robots.txt", |_, _| {
            let mut r = Response::ok("User-agent: *\nAllow: /\nSitemap: https://lunaric.dev/sitemap.xml\n")?;
            r.headers_mut().set("content-type", "text/plain; charset=utf-8")?;
            Ok(r)
        })
        .get_async("/api/ping", |_, _| async move {
            let body = r#"{"status":"ok","host":"lunaric.dev","runtime":"rust+wasm @ cloudflare edge"}"#;
            let mut resp = Response::ok(body)?;
            resp.headers_mut().set("content-type", "application/json")?;
            Ok(resp)
        })
        .post_async("/api/hit", |mut req, ctx| async move {
            let path = req.text().await.unwrap_or_default();
            if valid_path(&path) {
                let _ = record_hit(&ctx.env, &path).await;
            }
            Response::ok("")
        })
        .get_async("/stats", |_, ctx| async move {
            let rows = list_hits(&ctx.env).await.unwrap_or_default();
            Response::from_html(stats_page(&rows))
        })
        .run(req, env)
        .await?;
    let resp = if resp.status_code() == 404 { not_found() } else { resp };
    Ok(secure(resp))
}

fn not_found() -> Response {
    let inner = r#"<h1>404 <span class="accent">// not found</span></h1>
<p class="lead">This path doesn't exist — or you don't have clearance.</p>
<p>Head back to <a href="/">~</a>, or try <a href="/blog">/blog</a> and <a href="/whoami">/whoami</a>.</p>"#;
    let html = layout("", "404", "Page not found.", "/404", "", inner);
    match Response::from_html(html) {
        Ok(r) => r.with_status(404),
        Err(_) => Response::error("Not found", 404).unwrap(),
    }
}

// ---------- security headers ----------

// Sources allowed: own origin, Google Fonts (CSS + font files), and cdnjs for
// highlight.js (script + theme). No inline scripts/styles → no 'unsafe-inline'.
const CSP: &str = "default-src 'self'; \
    script-src 'self'; \
    style-src 'self'; \
    font-src 'self'; \
    img-src 'self' data: https:; \
    connect-src 'self'; \
    base-uri 'none'; \
    form-action 'self'; \
    frame-ancestors 'none'; \
    object-src 'none'; \
    upgrade-insecure-requests";

fn secure(mut resp: Response) -> Response {
    let h = resp.headers_mut();
    let _ = h.set("Content-Security-Policy", CSP);
    let _ = h.set("X-Content-Type-Options", "nosniff");
    let _ = h.set("X-Frame-Options", "DENY");
    let _ = h.set("Referrer-Policy", "strict-origin-when-cross-origin");
    let _ = h.set(
        "Permissions-Policy",
        "geolocation=(), microphone=(), camera=(), payment=(), usb=(), interest-cohort=()",
    );
    let _ = h.set("Strict-Transport-Security", "max-age=63072000; includeSubDomains");
    let _ = h.set("Cross-Origin-Opener-Policy", "same-origin");
    resp
}

// ---------- D1: view counter + guestbook ----------

async fn bump_views(env: &Env, slug: &str) -> Result<i64> {
    let db = env.d1("DB")?;
    let count: Option<i64> = db
        .prepare(
            "INSERT INTO views (slug, count) VALUES (?1, 1) \
             ON CONFLICT(slug) DO UPDATE SET count = count + 1 RETURNING count",
        )
        .bind(&[JsValue::from(slug)])?
        .first(Some("count"))
        .await?;
    Ok(count.unwrap_or(0))
}

#[derive(Deserialize, Default)]
struct Entry {
    name: String,
    message: String,
    created: String,
}

async fn list_guestbook(env: &Env) -> Result<Vec<Entry>> {
    let db = env.d1("DB")?;
    db.prepare("SELECT name, message, created FROM guestbook ORDER BY id DESC LIMIT 100")
        .all()
        .await?
        .results::<Entry>()
}

async fn add_guestbook(env: &Env, name: &str, message: &str) -> Result<()> {
    let db = env.d1("DB")?;
    let mut name = clamp(name.trim(), 50);
    if name.is_empty() {
        name = "anonymous".to_string();
    }
    let message = clamp(message.trim(), 1000);
    db.prepare("INSERT INTO guestbook (name, message) VALUES (?1, ?2)")
        .bind(&[JsValue::from(name), JsValue::from(message)])?
        .run()
        .await?;
    Ok(())
}

async fn record_hit(env: &Env, path: &str) -> Result<()> {
    let db = env.d1("DB")?;
    db.prepare("INSERT INTO hits (path, count) VALUES (?1, 1) ON CONFLICT(path) DO UPDATE SET count = count + 1")
        .bind(&[JsValue::from(path)])?
        .run()
        .await?;
    Ok(())
}

#[derive(Deserialize, Default)]
struct Hit {
    path: String,
    count: i64,
}

async fn list_hits(env: &Env) -> Result<Vec<Hit>> {
    let db = env.d1("DB")?;
    db.prepare("SELECT path, count FROM hits ORDER BY count DESC")
        .all()
        .await?
        .results::<Hit>()
}

// only count known routes — stops the hits table from being spammed with junk paths
fn valid_path(p: &str) -> bool {
    const KNOWN: [&str; 7] = ["/", "/whoami", "/blog", "/projects", "/uses", "/guestbook", "/stats"];
    if KNOWN.contains(&p) {
        return true;
    }
    if let Some(slug) = p.strip_prefix("/blog/") {
        return !slug.is_empty() && RAW_POSTS.iter().any(|(s, _)| *s == slug);
    }
    false
}

fn field(form: &FormData, key: &str) -> String {
    match form.get(key) {
        Some(FormEntry::Field(s)) => s,
        _ => String::new(),
    }
}

fn clamp(s: &str, n: usize) -> String {
    s.chars().take(n).collect()
}

fn redirect_to(path: &str) -> Result<Response> {
    let h = Headers::new();
    h.set("Location", path)?;
    Ok(Response::empty()?.with_status(303).with_headers(h))
}

// ---------- posts ----------

struct Post {
    slug: String,
    title: String,
    date: String, // YYYY-MM-DD
    description: String,
    tags: Vec<String>,
    body: String,
    minutes: usize,
}

fn parse_post(slug: &str, raw: &str) -> Post {
    let raw = raw.trim_start_matches('\u{feff}');
    let mut title = slug.to_string();
    let mut date = String::new();
    let mut description = String::new();
    let mut tags = Vec::new();
    let body;

    if let Some(rest) = raw.strip_prefix("---") {
        if let Some(end) = rest.find("\n---") {
            let fm = &rest[..end];
            let after = &rest[end + 4..];
            let start = after.find('\n').map(|i| i + 1).unwrap_or(after.len());
            body = after[start..].to_string();
            for line in fm.lines() {
                let line = line.trim();
                if let Some(v) = line.strip_prefix("title:") {
                    title = v.trim().to_string();
                } else if let Some(v) = line.strip_prefix("date:") {
                    date = v.trim().to_string();
                } else if let Some(v) = line.strip_prefix("description:") {
                    description = v.trim().to_string();
                } else if let Some(v) = line.strip_prefix("tags:") {
                    tags = v
                        .trim()
                        .trim_start_matches('[')
                        .trim_end_matches(']')
                        .split(',')
                        .map(|s| s.trim().to_string())
                        .filter(|s| !s.is_empty())
                        .collect();
                }
            }
        } else {
            body = raw.to_string();
        }
    } else {
        body = raw.to_string();
    }

    let minutes = (body.split_whitespace().count() / 200).max(1);
    Post { slug: slug.to_string(), title, date, description, tags, body, minutes }
}

fn all_posts() -> Vec<Post> {
    let mut v: Vec<Post> = RAW_POSTS.iter().map(|(s, r)| parse_post(s, r)).collect();
    v.sort_by(|a, b| b.date.cmp(&a.date));
    v
}

fn find_post(slug: &str) -> Option<Post> {
    RAW_POSTS.iter().find(|(s, _)| *s == slug).map(|(s, r)| parse_post(s, r))
}

fn render_md(md: &str) -> String {
    let mut o = Options::default();
    o.extension.strikethrough = true;
    o.extension.table = true;
    o.extension.autolink = true;
    o.extension.tasklist = true;
    o.extension.footnotes = true;
    o.render.r#unsafe = true;
    markdown_to_html(md, &o)
}

// ---------- helpers ----------

fn esc(s: &str) -> String {
    s.replace('&', "&amp;").replace('<', "&lt;").replace('>', "&gt;")
}

fn att(s: &str) -> String {
    esc(s).replace('"', "&quot;")
}

fn short_date(d: &str) -> String {
    let p: Vec<&str> = d.split('-').collect();
    if p.len() == 3 {
        let m = match p[1] {
            "01" => "Jan", "02" => "Feb", "03" => "Mar", "04" => "Apr",
            "05" => "May", "06" => "Jun", "07" => "Jul", "08" => "Aug",
            "09" => "Sep", "10" => "Oct", "11" => "Nov", "12" => "Dec",
            _ => p[1],
        };
        format!("{m} {}", p[0])
    } else if d.is_empty() {
        "—".to_string()
    } else {
        d.to_string()
    }
}

fn tags_html(tags: &[String]) -> String {
    tags.iter().map(|t| format!("<span class=\"tag\">{}</span>", esc(t))).collect::<String>()
}

fn post_row(p: &Post) -> String {
    format!(
        "<li><span class=\"date\">{date}</span><a href=\"/blog/{slug}\">{title}</a>{tags}</li>",
        date = short_date(&p.date),
        slug = p.slug,
        title = esc(&p.title),
        tags = tags_html(&p.tags),
    )
}

// ---------- pages ----------

fn home_page() -> String {
    let posts = all_posts();
    let latest = if posts.is_empty() {
        "<p class=\"out\">Posts coming soon.</p>".to_string()
    } else {
        format!("<ul class=\"posts\">{}</ul>", posts.iter().take(3).map(post_row).collect::<String>())
    };
    let inner = format!("{HOME_TOP}\n<h2>// latest</h2>\n{latest}");
    layout("~", "whoami", SITE_DESC, "/", "", &inner)
}

fn blog_index() -> String {
    let posts = all_posts();
    let list = if posts.is_empty() {
        "<p class=\"out\">No posts yet.</p>".to_string()
    } else {
        format!("<ul class=\"posts\">{}</ul>", posts.iter().map(post_row).collect::<String>())
    };
    let inner = format!(
        "<h1>// blog</h1>\n<p class=\"lead\">Notes, writeups, and the occasional deep dive.</p>\n{list}"
    );
    layout("blog", "blog", "Security writeups, projects, and homelab notes.", "/blog", "", &inner)
}

fn post_page(p: &Post, views: i64) -> String {
    let inner = format!(
        "<a class=\"back\" href=\"/blog\">← all posts</a>\n<h1>{title}</h1>\n\
         <div class=\"post-meta\"><span>{date}</span><span>{min} min read</span>\
         <span>{views} views</span>{tags}</div>\n\
         <article>{body}</article>",
        title = esc(&p.title),
        date = short_date(&p.date),
        min = p.minutes,
        views = views,
        tags = tags_html(&p.tags),
        body = render_md(&p.body),
    );
    let head = "<link rel=\"stylesheet\" href=\"/hljs-github-dark.css\"><script defer src=\"/hljs.min.js\"></script>";
    let desc = if p.description.is_empty() { SITE_DESC } else { p.description.as_str() };
    layout("blog", &p.title, desc, &format!("/blog/{}", p.slug), head, &inner)
}

fn guestbook_page(entries: &[Entry]) -> String {
    let list = if entries.is_empty() {
        "<p class=\"out\">No entries yet — be the first.</p>".to_string()
    } else {
        let rows = entries
            .iter()
            .map(|e| {
                format!(
                    "<li class=\"gb-entry\"><div class=\"gb-head\">\
                     <span class=\"gb-name\">{name}</span>\
                     <span class=\"gb-date\">{date} UTC</span></div>\
                     <p class=\"gb-msg\">{msg}</p></li>",
                    name = esc(&e.name),
                    date = esc(&e.created),
                    msg = esc(&e.message),
                )
            })
            .collect::<String>();
        format!("<ul class=\"gb-list\">{rows}</ul>")
    };
    let inner = format!(
        r#"<h1>// guestbook</h1>
<p class="lead">Leave a mark. Be nice.</p>
<form class="gb-form" method="post" action="/guestbook">
  <input class="gb-input" type="text" name="name" maxlength="50" placeholder="name (optional)" autocomplete="off">
  <input class="hp" type="text" name="website" tabindex="-1" autocomplete="off" aria-hidden="true">
  <textarea class="gb-input" name="message" maxlength="1000" rows="3" placeholder="message…" required></textarea>
  <button class="gb-btn" type="submit">sign</button>
</form>
{list}"#
    );
    layout("guestbook", "guestbook", "Sign the guestbook — say hi.", "/guestbook", "", &inner)
}

fn stats_page(rows: &[Hit]) -> String {
    let total: i64 = rows.iter().map(|h| h.count).sum();
    let list = if rows.is_empty() {
        "<p class=\"out\">No views recorded yet.</p>".to_string()
    } else {
        let items = rows
            .iter()
            .map(|h| {
                format!(
                    "<li><span class=\"date\">{count}</span><a href=\"{p}\">{p}</a></li>",
                    count = h.count,
                    p = esc(&h.path),
                )
            })
            .collect::<String>();
        format!("<ul class=\"posts\">{items}</ul>")
    };
    let inner = format!(
        "<h1>// stats</h1>\n<p class=\"lead\">{total} page views · self-hosted on D1, no third-party trackers.</p>\n{list}"
    );
    layout("", "stats", "Site analytics — self-hosted, privacy-first.", "/stats", "", &inner)
}

fn rss() -> String {
    let items = all_posts()
        .iter()
        .map(|p| {
            format!(
                "<item><title>{t}</title><link>https://lunaric.dev/blog/{s}</link>\
                 <guid>https://lunaric.dev/blog/{s}</guid><pubDate>{d}</pubDate>\
                 <description>{desc}</description></item>",
                t = esc(&p.title),
                s = p.slug,
                d = esc(&p.date),
                desc = esc(&p.description),
            )
        })
        .collect::<String>();
    format!(
        "<?xml version=\"1.0\" encoding=\"UTF-8\"?>\
         <rss version=\"2.0\"><channel><title>lunaric.dev</title>\
         <link>https://lunaric.dev</link>\
         <description>Security writeups, projects, and homelab notes.</description>{items}</channel></rss>"
    )
}

fn sitemap() -> String {
    let mut urls = vec![
        "".to_string(),
        "/whoami".into(),
        "/blog".into(),
        "/projects".into(),
        "/uses".into(),
        "/guestbook".into(),
    ];
    for p in all_posts() {
        urls.push(format!("/blog/{}", p.slug));
    }
    let body = urls
        .iter()
        .map(|u| format!("<url><loc>https://lunaric.dev{u}</loc></url>"))
        .collect::<String>();
    format!(
        "<?xml version=\"1.0\" encoding=\"UTF-8\"?>\
         <urlset xmlns=\"http://www.sitemaps.org/schemas/sitemap/0.9\">{body}</urlset>"
    )
}

// ---------- layout ----------

fn nav(active: &str) -> String {
    [
        ("whoami", "/whoami"),
        ("blog", "/blog"),
        ("projects", "/projects"),
        ("uses", "/uses"),
        ("guestbook", "/guestbook"),
    ]
    .iter()
    .map(|(label, href)| {
        let cur = if *label == active { " class=\"on\"" } else { "" };
        format!("<a href=\"{href}\"{cur}>{label}</a>")
    })
    .collect::<String>()
}

fn layout(active: &str, title: &str, desc: &str, path: &str, head_extra: &str, inner: &str) -> String {
    let page_title = att(&format!("{title} · lunaric.dev"));
    let desc = att(desc);
    let og_image = match path.strip_prefix("/blog/") {
        Some(slug) if !slug.is_empty() => format!("https://lunaric.dev/og/{slug}.png"),
        _ => "https://lunaric.dev/og/default.png".to_string(),
    };
    format!(
        r#"<!doctype html>
<html lang="en">
<head>
<meta charset="utf-8">
<meta name="viewport" content="width=device-width, initial-scale=1">
<title>{pt}</title>
<meta name="description" content="{desc}">
<link rel="canonical" href="https://lunaric.dev{path}">
<meta property="og:type" content="website">
<meta property="og:site_name" content="lunaric.dev">
<meta property="og:title" content="{pt}">
<meta property="og:description" content="{desc}">
<meta property="og:url" content="https://lunaric.dev{path}">
<meta property="og:image" content="{og_image}">
<meta name="twitter:card" content="summary_large_image">
<meta name="twitter:creator" content="@11lunaric11">
<meta name="twitter:title" content="{pt}">
<meta name="twitter:description" content="{desc}">
<meta name="twitter:image" content="{og_image}">
<link rel="alternate" type="application/rss+xml" title="lunaric.dev" href="/rss.xml">
<script src="/theme.js"></script>
<link rel="stylesheet" href="/fonts.css">
<link rel="stylesheet" href="/styles.css">
{head_extra}
</head>
<body>
<div class="wrap">
<nav><a class="brand" href="/">lunaric</a><span class="nav-links">{nav}</span></nav>
<main>
{inner}
</main>
<footer>
<span>© 2026 Dejan · built in rust</span>
<a href="/rss.xml">rss</a>
<a href="/stats">stats</a>
<a href="https://github.com/11lunaric11">github</a>
<span class="spacer"><span id="clock">--:--:--</span></span>
</footer>
</div>
<script defer src="/term.js"></script>
</body>
</html>"#,
        pt = page_title,
        desc = desc,
        nav = nav(active),
    )
}

